from math import gcd

class Solution(object):
    def isReachable(self, targetX, targetY):
        """
        :type targetX: int
        :type targetY: int
        :rtype: bool
        """
        # Work backwards from target to (1, 1)
        # Operations become: (x, y) -> (x+y, y), (x, y+x), (x/2, y), (x, y/2)

        while targetX != targetY:
            if targetX > targetY:
                # Reduce targetX by dividing by 2 repeatedly or via subtraction
                # If targetX is even, we can divide by 2
                # Otherwise, we need to subtract targetY repeatedly
                if targetX % 2 == 0:
                    targetX //= 2
                else:
                    # If targetY >= targetX, we can't make progress
                    if targetY >= targetX:
                        return False
                    # Subtract targetY as many times as possible
                    targetX -= (targetX // targetY) * targetY
            else:
                # Similar logic for targetY
                if targetY % 2 == 0:
                    targetY //= 2
                else:
                    if targetX >= targetY:
                        return False
                    targetY -= (targetY // targetX) * targetX

        # Both should be equal and it should be a power of 2 if starting from 1
        # Actually, they both need to reach the same power of 2
        # Check if the common value is a power of 2
        return targetX & (targetX - 1) == 0
